import React, { useState, useEffect } from 'react';
import {
    Container,
    Box,
    Typography,
    TextField,
    Button,
    MenuItem,
    Paper,
    CircularProgress,
    Alert
} from '@mui/material';
import { Build, ContentCopy } from '@mui/icons-material';
import { useVoiceControl } from '../context/VoiceControlContext';
import apiService from '../services/apiService';

const CodeCraftingPage = () => {
    const { speakFeedback } = useVoiceControl();
    const [description, setDescription] = useState('');
    const [language, setLanguage] = useState('python');
    const [generatedCode, setGeneratedCode] = useState('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    const languages = [
        { value: 'python', label: 'Python' },
        { value: 'javascript', label: 'JavaScript' },
        { value: 'typescript', label: 'TypeScript' },
        { value: 'java', label: 'Java' },
        { value: 'cpp', label: 'C++' },
        { value: 'go', label: 'Go' },
        { value: 'rust', label: 'Rust' },
        { value: 'csharp', label: 'C#' },
        { value: 'php', label: 'PHP' },
        { value: 'ruby', label: 'Ruby' }
    ];

    useEffect(() => {
        const handleVoiceAction = (event) => {
            const action = typeof event.detail === 'string' ? event.detail : event.detail?.action;
            
            if (action === 'craft' || action === 'generate') {
                handleCraft();
            } else if (action === 'copy') {
                handleCopy();
            } else if (action === 'clear') {
                handleClear();
            }
        };

        window.addEventListener('voicePageAction', handleVoiceAction);
        return () => window.removeEventListener('voicePageAction', handleVoiceAction);
    }, [description, language, generatedCode]);

    const handleCraft = async () => {
        if (!description.trim()) {
            setError('Please describe what code you want to generate');
            speakFeedback('Please describe what code you want to generate');
            return;
        }

        setLoading(true);
        setError('');
        speakFeedback('Crafting your code');

        try {
            const response = await apiService.generateCode({
                description: description,
                language: language
            });

            if (response.data && response.data.code) {
                setGeneratedCode(response.data.code);
                speakFeedback('Code crafted successfully');
            } else {
                throw new Error('No code returned from API');
            }
        } catch (err) {
            console.error('Code crafting error:', err);
            const errorMsg = err.response?.data?.detail || 'Failed to craft code';
            setError(errorMsg);
            speakFeedback('Failed to craft code. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    const handleCopy = () => {
        if (generatedCode) {
            navigator.clipboard.writeText(generatedCode);
            speakFeedback('Code copied to clipboard');
        }
    };

    const handleClear = () => {
        setDescription('');
        setGeneratedCode('');
        setError('');
        speakFeedback('Cleared');
    };

    return (
        <Container maxWidth="xl" sx={{ py: 4 }}>
            <Box sx={{ mb: 4 }}>
                <Typography variant="h3" gutterBottom sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                    <Build fontSize="large" />
                    Code Crafting
                </Typography>
                <Typography variant="body1" color="text.secondary">
                    Describe the code and the logic, and we'll generate it using Groq AI
                </Typography>
            </Box>

            {error && (
                <Alert severity="error" sx={{ mb: 3 }} onClose={() => setError('')}>
                    {error}
                </Alert>
            )}

            <Paper elevation={3} sx={{ p: 3, mb: 3 }}>
                <TextField
                    fullWidth
                    multiline
                    rows={6}
                    label="Code Description"
                    placeholder="e.g., Write a Python function that merges two sorted arrays, or Create a REST API endpoint in Node.js for user authentication"
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    sx={{ mb: 3 }}
                />

                <Box sx={{ display: 'flex', gap: 2, alignItems: 'center' }}>
                    <TextField
                        select
                        label="Language"
                        value={language}
                        onChange={(e) => setLanguage(e.target.value)}
                        sx={{ minWidth: 200 }}
                    >
                        {languages.map((lang) => (
                            <MenuItem key={lang.value} value={lang.value}>
                                {lang.label}
                            </MenuItem>
                        ))}
                    </TextField>

                    <Button
                        variant="contained"
                        size="large"
                        startIcon={loading ? <CircularProgress size={20} color="inherit" /> : <Build />}
                        onClick={handleCraft}
                        disabled={loading || !description.trim()}
                    >
                        {loading ? 'Crafting...' : 'Craft Code'}
                    </Button>

                    {generatedCode && (
                        <>
                            <Button
                                variant="outlined"
                                startIcon={<ContentCopy />}
                                onClick={handleCopy}
                            >
                                Copy
                            </Button>
                            <Button
                                variant="outlined"
                                onClick={handleClear}
                            >
                                Clear
                            </Button>
                        </>
                    )}
                </Box>
            </Paper>

            {generatedCode && (
                <Paper elevation={3} sx={{ p: 3 }}>
                    <Typography variant="h6" gutterBottom>
                        Generated Code:
                    </Typography>
                    <Box
                        component="pre"
                        sx={{
                            backgroundColor: '#1e1e1e',
                            color: '#d4d4d4',
                            padding: 2,
                            borderRadius: 1,
                            overflow: 'auto',
                            maxHeight: '500px',
                            fontFamily: 'Consolas, Monaco, "Courier New", monospace',
                            fontSize: '14px',
                            lineHeight: 1.5
                        }}
                    >
                        <code>{generatedCode}</code>
                    </Box>
                </Paper>
            )}

            <Box sx={{ mt: 3 }}>
                <Typography variant="body2" color="text.secondary" sx={{ fontStyle: 'italic' }}>
                    💡 Voice Commands: "craft" or "generate" to create code, "copy" to copy to clipboard, "clear" to reset
                </Typography>
            </Box>
        </Container>
    );
};

export default CodeCraftingPage;
